import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useSearchParams, useLocation } from 'react-router-dom';
import Navbar from './components/Navbar';
import CustomerMenu from './pages/CustomerMenu';
import CartPage from './pages/CartPage';
import OwnerDashboard from './pages/OwnerDashboard';
import PaymentDemo from './pages/PaymentDemo';
import Login from './pages/Login';
import VerifyOtp from './pages/VerifyOtp';
import SuperAdminDashboard from './pages/SuperAdminDashboard';
import StaffDashboard from './pages/StaffDashboard';
import OwnerSetup from './pages/OwnerSetup';
import OwnerProfilePage from './pages/OwnerProfilePage';
import ProtectedRoute from './components/ProtectedRoute';
import { AuthProvider } from './context/AuthContext';
import './styles/App.css';

function AppContent() {
  const [cart, setCart] = useState([]);
  const [searchParams] = useSearchParams();
  const location = useLocation();
  const tableParam = searchParams.get('table');

  // Synchronously initialize table number state from query param or session storage
  const [tableNumber, setTableNumber] = useState(() => {
    return tableParam || sessionStorage.getItem('tableNumber') || '';
  });

  // Sync tableNumber state when search parameter changes reactively
  useEffect(() => {
    if (tableParam) {
      setTableNumber(tableParam);
      sessionStorage.setItem('tableNumber', tableParam);
      console.log(`Updated table number from URL: ${tableParam}`);
    }
  }, [tableParam]);

  // Cart operations
  const addToCart = (item) => {
    setCart((prevCart) => {
      const existing = prevCart.find((cartItem) => cartItem.item.id === item.id);
      if (existing) {
        return prevCart.map((cartItem) =>
          cartItem.item.id === item.id
            ? { ...cartItem, quantity: cartItem.quantity + 1 }
            : cartItem
        );
      }
      return [...prevCart, { item, quantity: 1 }];
    });
  };

  const increaseQuantity = (id) => {
    setCart((prevCart) =>
      prevCart.map((cartItem) =>
        cartItem.item.id === id
          ? { ...cartItem, quantity: cartItem.quantity + 1 }
          : cartItem
      )
    );
  };

  const decreaseQuantity = (id) => {
    setCart((prevCart) => {
      const existing = prevCart.find((cartItem) => cartItem.item.id === id);
      if (existing && existing.quantity === 1) {
        // Remove item if quantity becomes 0
        return prevCart.filter((cartItem) => cartItem.item.id !== id);
      }
      return prevCart.map((cartItem) =>
        cartItem.item.id === id
          ? { ...cartItem, quantity: cartItem.quantity - 1 }
          : cartItem
      );
    });
  };

  const removeFromCart = (id) => {
    setCart((prevCart) => prevCart.filter((cartItem) => cartItem.item.id !== id));
  };

  const clearCart = () => {
    setCart([]);
  };

  const totalItemCount = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  // Determine if we are on an administrative or auth portal page to hide customer elements
  const isAdminOrAuthRoute = 
    location.pathname.startsWith('/admin') ||
    location.pathname.startsWith('/owner') ||
    location.pathname.startsWith('/super-admin') ||
    location.pathname.startsWith('/staff') ||
    ['/login', '/verify-otp'].includes(location.pathname);

  return (
    <div className={`app-container${isAdminOrAuthRoute ? ' admin-no-padding' : ''}`}>
      {!isAdminOrAuthRoute && (
        <Navbar tableNumber={tableNumber} cartItemCount={totalItemCount} />
      )}
      
      <main className={`main-content${isAdminOrAuthRoute ? ' admin-full-width' : ''}`}>
        <Routes>
          {/* Customer / Ordering Flow */}
          <Route 
            path="/" 
            element={
              tableNumber ? (
                <CustomerMenu 
                  cart={cart}
                  addToCart={addToCart}
                  increaseQuantity={increaseQuantity}
                  decreaseQuantity={decreaseQuantity}
                />
              ) : (
                <Navigate to="/login" replace />
              )
            } 
          />
          <Route 
            path="/cart" 
            element={
              <CartPage 
                cart={cart}
                increaseQuantity={increaseQuantity}
                decreaseQuantity={decreaseQuantity}
                removeFromCart={removeFromCart}
                clearCart={clearCart}
                tableNumber={tableNumber}
              />
            } 
          />

          {/* Auth Flow */}
          <Route path="/login" element={<Login />} />
          <Route path="/verify-otp" element={<VerifyOtp />} />

          {/* Role Protected Admin Dashboards */}
          <Route 
            path="/super-admin" 
            element={
              <ProtectedRoute allowedRoles={['super_admin']}>
                <SuperAdminDashboard />
              </ProtectedRoute>
            } 
          />
          <Route 
            path="/owner-setup" 
            element={
              <ProtectedRoute allowedRoles={['admin']}>
                <OwnerSetup />
              </ProtectedRoute>
            } 
          />
          <Route 
            path="/admin" 
            element={
              <ProtectedRoute allowedRoles={['admin']}>
                <OwnerDashboard />
              </ProtectedRoute>
            } 
          />
          <Route 
            path="/owner/profile" 
            element={
              <ProtectedRoute allowedRoles={['admin']}>
                <OwnerProfilePage />
              </ProtectedRoute>
            } 
          />
          <Route 
            path="/staff" 
            element={
              <ProtectedRoute allowedRoles={['staff']}>
                <StaffDashboard />
              </ProtectedRoute>
            } 
          />

          {/* Legacy & Demo routes */}
          <Route 
            path="/payment-demo" 
            element={<PaymentDemo />} 
          />
          <Route 
            path="/dashboard" 
            element={<Navigate to="/admin" replace />} 
          />
        </Routes>
      </main>
    </div>
  );
}

function App() {
  return (
    <Router>
      <AuthProvider>
        <AppContent />
      </AuthProvider>
    </Router>
  );
}

export default App;

import React from 'react';

const CartItem = ({ item, increaseQuantity, decreaseQuantity, removeFromCart }) => {
  const { id, name, image, price } = item.item;
  const { quantity } = item;

  return (
    <div className="cart-item-card">
      <img src={image} alt={name} className="cart-item-img" />

      <div className="cart-item-info">
        <h4 className="cart-item-name">{name}</h4>
        <div className="cart-item-price">${price.toFixed(2)} each</div>
      </div>

      <div className="cart-item-right">
        <div className="qty-control">
          <button 
            onClick={() => decreaseQuantity(id)} 
            className="qty-btn"
            aria-label="Decrease quantity"
          >
            -
          </button>
          <span className="qty-val">{quantity}</span>
          <button 
            onClick={() => increaseQuantity(id)} 
            className="qty-btn"
            aria-label="Increase quantity"
          >
            +
          </button>
        </div>

        <button 
          onClick={() => removeFromCart(id)} 
          className="btn-remove"
          title="Remove item"
          aria-label="Remove item"
        >
          🗑️
        </button>
      </div>
    </div>
  );
};

export default CartItem;

import React from 'react';

const MenuCard = ({ item, cartItem, addToCart, increaseQuantity, decreaseQuantity }) => {
  const { id, name, image, price, category, description, available } = item;

  return (
    <div className="menu-card">
      {!available && (
        <div className="out-of-stock-overlay">
          <span className="out-of-stock-badge">Out of Stock</span>
        </div>
      )}

      <div className="menu-card-img-container">
        <img src={image} alt={name} className="menu-card-img" />
        <span className="menu-card-badge">{category}</span>
      </div>

      <div className="menu-card-content">
        <div className="menu-card-header">
          <h3 className="menu-card-title">{name}</h3>
          <span className="menu-card-price">${price.toFixed(2)}</span>
        </div>

        <p className="menu-card-description">{description}</p>

        <div className="menu-card-footer">
          {cartItem ? (
            <div className="qty-control">
              <button 
                onClick={() => decreaseQuantity(id)} 
                className="qty-btn"
                aria-label="Decrease quantity"
              >
                -
              </button>
              <span className="qty-val">{cartItem.quantity}</span>
              <button 
                onClick={() => increaseQuantity(id)} 
                className="qty-btn"
                aria-label="Increase quantity"
              >
                +
              </button>
            </div>
          ) : (
            <button 
              onClick={() => addToCart(item)} 
              className={`btn btn-primary ${!available ? 'btn-disabled' : ''}`}
              disabled={!available}
            >
              Add to Cart
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default MenuCard;

import React from 'react';
import { Link } from 'react-router-dom';

const Navbar = ({ tableNumber, cartItemCount }) => {
  return (
    <nav className="navbar">
      <Link to="/" className="nav-brand" style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
        <img src="/logo.svg" alt="Dr. Chai Cafe Logo" style={{ height: '40px', width: '40px', borderRadius: '50%', objectFit: 'cover', border: '1px solid #6F4E37' }} />
        <span className="nav-brand-text">Dr. Chai Cafe</span>
      </Link>
      
      <div className="nav-right">
        <Link to="/payment-demo" className="nav-demo-link" style={{ marginRight: '15px', textDecoration: 'none', color: '#d4af37', fontWeight: '800', fontSize: '13px', display: 'flex', alignItems: 'center', gap: '4px' }}>
          💳 Demo
        </Link>
        
        {tableNumber && (
          <div className="table-badge">
            TABLE {tableNumber}
          </div>
        )}
        
        <Link to="/cart" className="nav-cart-icon" aria-label="View Cart">
          🛒
          {cartItemCount > 0 && (
            <span className="nav-cart-badge">{cartItemCount}</span>
          )}
        </Link>
      </div>
    </nav>
  );
};

export default Navbar;

import React from 'react';

const OrderCard = ({ order, onStatusUpdate }) => {
  const { _id, tableNumber, items, totalAmount, status, createdAt } = order;

  // Format time
  const formatTime = (dateStr) => {
    try {
      const date = new Date(dateStr);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch (e) {
      return '';
    }
  };

  return (
    <div className="order-card">
      <div className="order-card-header">
        <span className="order-table">Table {tableNumber}</span>
        <span className="order-time">{formatTime(createdAt)}</span>
      </div>

      <div className="order-items-list">
        {items.map((item, idx) => (
          <div key={idx} className="order-item-row">
            <span>
              {item.name} <span className="order-item-qty">x{item.quantity}</span>
            </span>
            <span>${(item.price * item.quantity).toFixed(2)}</span>
          </div>
        ))}
      </div>

      <div className="order-card-footer">
        <span className="order-total-label">Total Amount:</span>
        <span className="order-total-amount">${totalAmount.toFixed(2)}</span>
      </div>

      <div className="order-actions">
        {status === 'Preparing' ? (
          <button 
            onClick={() => onStatusUpdate(_id, 'Served')}
            className="btn btn-action btn-action-ready"
            style={{ width: '100%', padding: '12px', fontSize: '14px', fontWeight: 'bold' }}
          >
            🍽️ Serve Order
          </button>
        ) : (
          <button 
            className="btn btn-action btn-disabled"
            disabled
            style={{ width: '100%', padding: '12px', fontSize: '14px', fontWeight: 'bold', backgroundColor: '#1b4d3e', color: '#85e3b2', border: '1px solid #2e7d63' }}
          >
            ✓ Served & Completed
          </button>
        )}
      </div>
    </div>
  );
};

export default OrderCard;

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { getSetupData, getBranches } from '../services/api';

const OwnerLayout = ({ children }) => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [cafeName, setCafeName] = useState('My Cafe');
  const [logoUrl, setLogoUrl] = useState('');
  const [currentBranchName, setCurrentBranchName] = useState('Main Branch');

  // Load cafe header data on each page change
  useEffect(() => {
    const fetchHeaderData = async () => {
      try {
        const res = await getSetupData();
        if (res.success && res.cafe) {
          setCafeName(res.cafe.name || 'My Cafe');
          setLogoUrl(res.cafe.logoUrl || '');
          if (res.cafe.city) {
            setCurrentBranchName(`${res.cafe.city} Branch`);
          }
        }
        const branchRes = await getBranches();
        if (branchRes.success && branchRes.branches && branchRes.branches.length > 0) {
          const active = branchRes.branches.find(b => b.isActive) || branchRes.branches[0];
          setCurrentBranchName(active.branchName);
        }
      } catch (err) {
        // Silently fail — header still renders with defaults
      }
    };
    fetchHeaderData();
  }, [location.pathname]);

  // Get owner initials for avatar
  const getInitials = (name) => {
    if (!name) return 'OW';
    const parts = name.trim().split(' ');
    if (parts.length >= 2) return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
    return name.slice(0, 2).toUpperCase();
  };

  const isOnProfile = location.pathname === '/owner/profile';

  return (
    <div className="owner-layout-wrapper">
      <style>{`
        .owner-layout-wrapper {
          min-height: 100vh;
          background-color: #1F140E;
          font-family: 'Outfit', 'Inter', sans-serif;
          color: #FAF6F0;
        }

        /* ─── STICKY HEADER ─────────────────────────── */
        .owner-header {
          position: sticky;
          top: 0;
          z-index: 100;
          background: rgba(31, 20, 14, 0.92);
          backdrop-filter: blur(14px);
          -webkit-backdrop-filter: blur(14px);
          border-bottom: 1px solid rgba(230, 213, 195, 0.12);
          padding: 0 24px;
          height: 60px;
          display: flex;
          align-items: center;
          justify-content: space-between;
        }

        /* ─── LOGO / CAFE NAME — clickable → dashboard ─ */
        .header-brand {
          display: flex;
          align-items: center;
          gap: 12px;
          cursor: pointer;
          border-radius: 10px;
          padding: 6px 8px;
          margin-left: -8px;
          transition: background 0.2s;
          user-select: none;
          text-decoration: none;
        }
        .header-brand:hover {
          background: rgba(230, 213, 195, 0.07);
        }
        .header-brand:active {
          background: rgba(230, 213, 195, 0.12);
        }
        .cafe-logo-circle {
          width: 36px;
          height: 36px;
          border-radius: 50%;
          border: 2px solid rgba(230, 213, 195, 0.4);
          background: #2B1D15;
          overflow: hidden;
          display: flex;
          align-items: center;
          justify-content: center;
          flex-shrink: 0;
          font-size: 1rem;
        }
        .cafe-logo-circle img {
          width: 100%;
          height: 100%;
          object-fit: cover;
        }
        .cafe-meta {
          display: flex;
          flex-direction: column;
          gap: 1px;
        }
        .cafe-name-text {
          font-size: 1rem;
          font-weight: 800;
          color: #FAF6F0;
          line-height: 1.2;
          letter-spacing: -0.2px;
        }
        .cafe-branch-text {
          font-size: 0.72rem;
          font-weight: 600;
          color: #A0826C;
          line-height: 1;
        }

        /* ─── RIGHT SIDE — avatar only ─────────────────── */
        .header-avatar-btn {
          width: 38px;
          height: 38px;
          border-radius: 50%;
          background: linear-gradient(135deg, #6F4E37, #3E2723);
          border: 2px solid rgba(230, 213, 195, 0.5);
          color: #FAF6F0;
          font-weight: 800;
          font-size: 0.85rem;
          display: flex;
          align-items: center;
          justify-content: center;
          cursor: pointer;
          transition: transform 0.2s, box-shadow 0.2s, border-color 0.2s;
          flex-shrink: 0;
          font-family: inherit;
        }
        .header-avatar-btn:hover {
          transform: scale(1.08);
          box-shadow: 0 0 0 3px rgba(230, 213, 195, 0.2);
        }
        .header-avatar-btn.active {
          border-color: #E6D5C3;
          box-shadow: 0 0 0 3px rgba(230, 213, 195, 0.25);
        }

        /* ─── MAIN CONTENT ──────────────────────────── */
        .owner-main-content {
          width: 100%;
        }

        /* ─── SECTION HIGHLIGHT ANIMATION ──────────── */
        .highlight-section {
          animation: glowBorder 2s ease-out;
        }
        @keyframes glowBorder {
          0%, 100% { border-color: rgba(230, 213, 195, 0.12); box-shadow: none; }
          50% { border-color: #ff9800; box-shadow: 0 0 18px rgba(255, 152, 0, 0.25); }
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(6px); }
          to { opacity: 1; transform: translateY(0); }
        }

        /* ─── RESPONSIVE ────────────────────────────── */
        @media (max-width: 640px) {
          .owner-header {
            padding: 0 16px;
            height: 56px;
          }
          .cafe-name-text { font-size: 0.9rem; }
        }
      `}</style>

      {/* ─── HEADER ─────────────────────────────────── */}
      <header className="owner-header">
        {/* Brand / Logo → navigates to dashboard */}
        <div
          className="header-brand"
          onClick={() => navigate('/admin')}
          role="button"
          aria-label="Go to Dashboard"
        >
          <div className="cafe-logo-circle">
            {logoUrl ? (
              <img src={logoUrl} alt="Logo" />
            ) : (
              <span>☕</span>
            )}
          </div>
          <div className="cafe-meta">
            <span className="cafe-name-text">{cafeName}</span>
            <span className="cafe-branch-text">📍 {currentBranchName}</span>
          </div>
        </div>

        {/* Avatar → navigates to profile page */}
        <button
          className={`header-avatar-btn ${isOnProfile ? 'active' : ''}`}
          onClick={() => navigate('/owner/profile')}
          title={`${user?.name || 'Owner'} — View Profile`}
        >
          {getInitials(user?.name)}
        </button>
      </header>

      {/* ─── PAGE CONTENT ───────────────────────────── */}
      <main className="owner-main-content">
        {children}
      </main>
    </div>
  );
};

export default OwnerLayout;

import React from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

/**
 * Route protection wrapper based on authentication and user roles
 */
const ProtectedRoute = ({ children, allowedRoles }) => {
  const { user, loading } = useAuth();
  const location = useLocation();

  if (loading) {
    return (
      <div style={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        height: '80vh',
        fontFamily: "'Outfit', sans-serif",
        color: '#6F4E37'
      }}>
        <div style={{
          border: '4px solid #F3F3F3',
          borderTop: '4px solid #6F4E37',
          borderRadius: '50%',
          width: '40px',
          height: '40px',
          animation: 'spin 1s linear infinite',
          marginBottom: '15px'
        }} />
        <p style={{ fontWeight: '500' }}>Validating credentials...</p>
        <style>{`
          @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }
        `}</style>
      </div>
    );
  }

  // If not authenticated, redirect to login page
  if (!user) {
    return <Navigate to="/login" replace />;
  }

  // Onboarding Setup Safeguard Redirects
  // Allow /owner/profile even during setup so the owner can view/edit their profile anytime
  const setupBypassRoutes = ['/owner-setup', '/owner/profile'];
  if (user.role === 'admin') {
    if (user.setupCompleted === false && !setupBypassRoutes.includes(location.pathname)) {
      return <Navigate to="/owner-setup" replace />;
    }
    if (user.setupCompleted === true && location.pathname === '/owner-setup') {
      return <Navigate to="/admin" replace />;
    }
  }

  // If role is not permitted, redirect to their default home dashboard
  if (allowedRoles && !allowedRoles.includes(user.role)) {
    console.warn(`User role ${user.role} unauthorized for this view.`);

    if (user.role === 'super_admin') {
      return <Navigate to="/super-admin" replace />;
    } else if (user.role === 'admin') {
      return <Navigate to="/admin" replace />;
    } else if (user.role === 'staff') {
      return <Navigate to="/staff" replace />;
    }

    return <Navigate to="/" replace />;
  }

  return children;
};

export default ProtectedRoute;

import React, { useState, useEffect } from 'react';
import { createPaymentOrder, verifyPayment, payExistingOrder } from '../services/api';

const RazorpayPayment = ({
  cart,
  tableNumber,
  customerDetails,
  onPaymentSuccess,
  onPaymentError,
  isDisabled,
  existingOrderId,
  buttonText = 'Pay & Place Order'
}) => {
  const [loading, setLoading] = useState(false);
  const [scriptLoaded, setScriptLoaded] = useState(false);
  const [processingStatus, setProcessingStatus] = useState('');

  // Dynamically load Razorpay checkout script
  useEffect(() => {
    const loadScript = () => {
      if (window.Razorpay) {
        setScriptLoaded(true);
        return;
      }
      
      const script = document.createElement('script');
      script.src = 'https://checkout.razorpay.com/v1/checkout.js';
      script.async = true;
      script.onload = () => {
        setScriptLoaded(true);
        console.log('Razorpay Checkout SDK loaded successfully.');
      };
      script.onerror = () => {
        console.error('Failed to load Razorpay Checkout SDK.');
      };
      document.body.appendChild(script);
    };

    loadScript();
  }, []);

  const handlePayment = async () => {
    if (!scriptLoaded) {
      alert('Razorpay Checkout SDK is still loading. Please try again in a moment.');
      return;
    }

    const { name, email, phone } = customerDetails;
    if (!name || !email || !phone) {
      alert('Please fill in your name, email, and contact number before proceeding.');
      return;
    }

    setLoading(true);
    setProcessingStatus('Initiating transaction...');

    try {
      let orderData;
      if (existingOrderId) {
        // Pay for an existing order in the database
        orderData = await payExistingOrder({ appOrderId: existingOrderId });
      } else {
        // Create a new order during checkout
        const payload = {
          items: cart.map(cartItem => ({
            id: cartItem.item.id || cartItem.item._id,
            name: cartItem.item.name,
            price: cartItem.item.price,
            quantity: cartItem.quantity
          })),
          tableNumber: tableNumber || 'Takeaway',
          customerName: name,
          customerEmail: email,
          customerPhone: phone
        };

        orderData = await createPaymentOrder(payload);
      }
      
      if (!orderData.success) {
        throw new Error(orderData.message || 'Failed to initiate order payment on server.');
      }

      setProcessingStatus('Opening secure gateway...');

      // 2. Configure and Open Razorpay Checkout Modal
      const options = {
        key: orderData.keyId,
        amount: orderData.amount, // in paise
        currency: orderData.currency,
        name: 'Dr. Chai Cafe',
        description: `Cafe Order for Table ${tableNumber || 'Takeaway'}`,
        image: 'https://images.unsplash.com/photo-1509042239860-f550ce710b93?w=100&auto=format&fit=crop&q=60', // beautiful cafe logo icon
        order_id: orderData.razorpayOrderId,
        handler: async function (response) {
          // Payment successful inside checkout modal
          setProcessingStatus('Verifying payment signature...');
          
          try {
            const verificationPayload = {
              appOrderId: orderData.appOrderId,
              razorpayOrderId: response.razorpay_order_id,
              razorpayPaymentId: response.razorpay_payment_id,
              razorpaySignature: response.razorpay_signature
            };

            const verificationResult = await verifyPayment(verificationPayload);

            if (verificationResult.success) {
              setProcessingStatus('Success!');
              if (onPaymentSuccess) {
                onPaymentSuccess(verificationResult.data);
              }
            } else {
              throw new Error(verificationResult.message || 'Signature verification failed.');
            }
          } catch (verifyError) {
            console.error('Verification request failed:', verifyError);
            const errMsg = verifyError.response?.data?.message || verifyError.message || 'Signature verification error';
            if (onPaymentError) onPaymentError(errMsg);
          } finally {
            setLoading(false);
            setProcessingStatus('');
          }
        },
        prefill: {
          name: name,
          email: email,
          contact: phone
        },
        notes: {
          appOrderId: orderData.appOrderId
        },
        theme: {
          color: '#d4af37' // premium elegant cafe gold color
        },
        modal: {
          ondismiss: function () {
            setLoading(false);
            setProcessingStatus('');
            if (onPaymentError) {
              onPaymentError('Payment window was closed by the user.');
            }
          }
        }
      };

      const rzpInstance = new window.Razorpay(options);
      rzpInstance.open();

    } catch (error) {
      console.error('Razorpay payment initialization flow failed:', error);
      const errMsg = error.response?.data?.message || error.message || 'Payment initiation error';
      if (onPaymentError) onPaymentError(errMsg);
      setLoading(false);
      setProcessingStatus('');
    }
  };

  return (
    <div className="payment-checkout-container" style={{ width: '100%' }}>
      <button
        type="button"
        onClick={handlePayment}
        disabled={isDisabled || loading || !scriptLoaded}
        className={`btn btn-checkout-rzp ${isDisabled || loading || !scriptLoaded ? 'btn-disabled' : ''}`}
        style={{
          width: '100%',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          gap: '10px',
          padding: '14px 20px',
          fontSize: '16px',
          fontWeight: '800',
          borderRadius: '12px',
          border: 'none',
          cursor: (isDisabled || loading || !scriptLoaded) ? 'not-allowed' : 'pointer',
          background: 'linear-gradient(135deg, #d4af37 0%, #aa820a 100%)',
          color: '#fff',
          boxShadow: '0 6px 20px rgba(170, 130, 10, 0.3)',
          transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)'
        }}
      >
        {loading ? (
          <>
            <span className="spinner-rzp" style={{
              width: '20px',
              height: '20px',
              border: '3px solid rgba(255,255,255,0.3)',
              borderTop: '3px solid #ffffff',
              borderRadius: '50%',
              animation: 'spin 0.8s linear infinite',
              display: 'inline-block'
            }}></span>
            <span>{processingStatus || 'Processing...'}</span>
          </>
        ) : (
          <>
            <span>💳</span>
            <span>{buttonText}</span>
          </>
        )}
      </button>
      
      {!scriptLoaded && (
        <p style={{
          fontSize: '11px',
          color: 'var(--color-text-secondary)',
          textAlign: 'center',
          marginTop: '6px'
        }}>
          Loading secure Razorpay SDK...
        </p>
      )}
    </div>
  );
};

export default RazorpayPayment;

import React, { createContext, useState, useEffect, useContext } from 'react';
import { getMe, sendOtp, verifyOtp, logoutUser } from '../services/api';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Check if user has an active session cookie on app boot
  const checkSession = async () => {
    try {
      setLoading(true);
      const data = await getMe();
      if (data.success && data.user) {
        setUser(data.user);
      } else {
        setUser(null);
      }
    } catch (err) {
      console.log('Session validation failed (not logged in):', err.message);
      setUser(null);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    checkSession();
  }, []);

  /**
   * Initiate passwordless login by sending an OTP
   */
  const initiateLogin = async (email) => {
    setError(null);
    try {
      const response = await sendOtp(email);
      return response;
    } catch (err) {
      const errMsg = err.response?.data?.message || 'Failed to send verification code. Please check your email.';
      setError(errMsg);
      throw new Error(errMsg);
    }
  };

  /**
   * Verify the OTP and authenticate the user
   */
  const confirmOtp = async (email, otp) => {
    setError(null);
    try {
      const response = await verifyOtp(email, otp);
      if (response.success && response.user) {
        setUser(response.user);
      }
      return response;
    } catch (err) {
      const errMsg = err.response?.data?.message || 'Incorrect verification code. Please try again.';
      setError(errMsg);
      throw new Error(errMsg);
    }
  };

  /**
   * Log out the active session
   */
  const logout = async () => {
    try {
      await logoutUser();
    } catch (err) {
      console.error('Logout request failed:', err);
    } finally {
      setUser(null);
    }
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        loading,
        error,
        initiateLogin,
        confirmOtp,
        logout,
        checkSession,
        setUser
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export default AuthContext;

