        .branch-item { display:flex; justify-content:space-between; align-items:center; padding:10px 0; border-bottom:1px solid rgba(230,213,195,.06); }
        .branch-name { font-weight:700; color:#E6D5C3; font-size:.875rem; }
        .branch-addr { font-size:.75rem; color:#7A6055; margin-top:2px; }
        .badge-on  { background:rgba(46,204,113,.15); color:#2ecc71; padding:2px 9px; border-radius:20px; font-size:.7rem; font-weight:700; }
        .badge-off { background:rgba(255,255,255,.06); color:#5C4030; padding:2px 9px; border-radius:20px; font-size:.7rem; font-weight:700; }
        .add-branch-row { padding-top:12px; }
        .btn-add { background:transparent; border:1px dashed rgba(111,78,55,.4); color:#6F4E37; padding:9px; border-radius:9px; font-weight:700; font-size:.82rem; cursor:pointer; width:100%; font-family:inherit; transition:all .2s; }
        .btn-add:hover { border-color:#6F4E37; color:#E6D5C3; background:rgba(111,78,55,.08); }

        /* toast */
        .toast { position:fixed; top:20px; left:50%; transform:translateX(-50%); z-index:9999; padding:11px 22px; border-radius:10px; font-weight:700; font-size:.875rem; box-shadow:0 8px 24px rgba(0,0,0,.5); animation:fadeIn .25s ease; white-space:nowrap; }
        .tok { background:#27ae60; color:#fff; }
        .terr { background:#e74c3c; color:#fff; }

        .spinner { width:36px; height:36px; border:3px solid rgba(111,78,55,.2); border-top-color:#6F4E37; border-radius:50%; animation:spin 1s linear infinite; margin:80px auto; }
        @keyframes spin { to{transform:rotate(360deg)} }
      `}</style>

      {toast && <div className={`toast ${toast.ok ? 'tok' : 'terr'}`}>{toast.ok ? '✓' : '⚠'} {toast.msg}</div>}

      <div className="pp">
        {loading ? <div className="spinner" /> : <>

          {/* Banner */}
          <div className="pp-banner">
            <div className="pp-avatar-wrap">
              <div className="pp-avatar">{cafeData?.logoUrl ? <img src={cafeData.logoUrl} alt="cafe" /> : '☕'}</div>
              <div className="pp-identity">
                <h2>{cafeData?.name || 'My Cafe'}</h2>
                <p>{cafeData?.cafeId} · {cafeData?.businessType || 'Cafe'}</p>
              </div>
            </div>
          </div>

          {/* Progress */}
          {!cafeData?.setupCompleted && (
            <div className="pp-prog">
              <span>Setup {cafeData?.address ? '60' : '20'}%</span>
              <div className="prog-outer"><div className="prog-inner" style={{ width: cafeData?.address ? '60%' : '20%' }} /></div>
              <button className="btn-setup" onClick={() => navigate('/owner-setup')}>🚀 Continue Setup</button>
            </div>
          )}

          {/* Card Grid */}
          <div className="card-grid">
            {cards.map(({ key, icon, title, rows }) => (
              <div key={key} className="sec-card" onClick={() => openModal(key)} role="button" aria-label={`Edit ${title}`}>
                <div className="sec-card-head">
                  <span className="sec-card-icon">{icon}</span>
                  <span className="sec-card-title">{title}</span>
                  <span className="sec-card-edit">Tap to edit ›</span>
                </div>
                {rows.map(([label, value]) => (
                  <div key={label} className="sec-row">
                    <span className="sec-row-label">{label}</span>
                    <span className={`sec-row-value ${!value || value === '—' ? 'sec-row-empty' : ''}`}>{value || '—'}</span>
                  </div>
                ))}
              </div>
            ))}

            {/* Branches card — full width */}
            <div className="sec-card sec-card-full">
              <div className="sec-card-head">
                <span className="sec-card-icon">🌿</span>
                <span className="sec-card-title">Branches ({branches.length})</span>
              </div>
              {branches.length === 0 && <p style={{ color:'#3D2820', fontStyle:'italic', fontSize:'.85rem', margin:'4px 0 10px' }}>No branches added yet.</p>}
              {branches.map(b => (
                <div key={b._id} className="branch-item">
                  <div>
                    <div className="branch-name">{b.branchName}</div>
                    <div className="branch-addr">{b.address}{b.manager ? ` · ${b.manager}` : ''}</div>
                  </div>
                  <span className={b.isActive ? 'badge-on' : 'badge-off'}>{b.isActive ? 'Active' : 'Inactive'}</span>
                </div>
              ))}
              <div className="add-branch-row">
                <button className="btn-add" onClick={(e) => { e.stopPropagation(); openModal('branch'); }}>＋ Add New Branch</button>
              </div>
            </div>
          </div>

          {/* Sign Out Button */}
          <div style={{ marginTop: '40px', textAlign: 'center' }}>
            <button 
              onClick={() => {
                if(window.confirm('Are you sure you want to sign out?')) {
                  logout();
                }
              }}
              style={{ 
                background: 'transparent', 
                border: '1px solid rgba(231, 76, 60, 0.5)', 
                color: '#E74C3C', 
                padding: '12px 30px', 
                borderRadius: '8px', 
                cursor: 'pointer', 
                fontWeight: 700,
                fontSize: '0.9rem',
                transition: 'all 0.2s',
                fontFamily: 'inherit'
              }}
              onMouseOver={(e) => {
                e.currentTarget.style.background = 'rgba(231, 76, 60, 0.1)';
                e.currentTarget.style.borderColor = '#E74C3C';
              }}
              onMouseOut={(e) => {
                e.currentTarget.style.background = 'transparent';
                e.currentTarget.style.borderColor = 'rgba(231, 76, 60, 0.5)';
              }}
            >
              Sign Out
            </button>
          </div>
        </>}
      </div>

      {/* ── Modal ── */}
      {activeModal && (
        <div className="moverlay" onClick={closeModal}>
          <div className="mcard" onClick={e => e.stopPropagation()}>
            <div className="mhead">
              <h3>{modalTitles[activeModal]}</h3>
              <button className="mclose" onClick={closeModal}>✕</button>
            </div>
            {modalFields[activeModal]}
            <div className="mfooter">
              <button className="mbtn-cancel" onClick={closeModal}>Cancel</button>
              <button className="mbtn-save" onClick={saveModal} disabled={saving}>{saving ? 'Saving…' : 'Save Changes'}</button>
            </div>
          </div>
        </div>
      )}
    </OwnerLayout>
  );
};

export default OwnerProfilePage;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { getSetupData, saveSetupData, verifyRazorpayKeys, uploadLogo } from '../services/api';

const OwnerSetup = () => {
  const { user, checkSession } = useAuth();
  const navigate = useNavigate();

  // Wizard active step (1 to 5)
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  // Step 1: Cafe Profile States
  const [cafeName, setCafeName] = useState('');
  const [logoFile, setLogoFile] = useState(null);
  const [logoPreview, setLogoPreview] = useState('/logo.svg');
  const [logoUrl, setLogoUrl] = useState('');
  const [address, setAddress] = useState('');
  const [mapsLocation, setMapsLocation] = useState('40.7128,-74.0060'); // Default GPS coordinates
  const [openingTime, setOpeningTime] = useState('08:00');
  const [closingTime, setClosingTime] = useState('22:00');
  const [gstNumber, setGstNumber] = useState('');
  const [supportNumber, setSupportNumber] = useState('');

  // Step 2: Payment Setup States
  const [razorpayKeyId, setRazorpayKeyId] = useState('');
  const [razorpaySecret, setRazorpaySecret] = useState('');
  const [upiId, setUpiId] = useState('');
  const [bankHolderName, setBankHolderName] = useState('');
  const [accountNumber, setAccountNumber] = useState('');
  const [ifscCode, setIfscCode] = useState('');
  const [isRazorpayVerified, setIsRazorpayVerified] = useState(false);
  const [verifyingKeys, setVerifyingKeys] = useState(false);

  // Step 3: Operational Setup States
  const [tableCount, setTableCount] = useState(5);
  const [tablesList, setTablesList] = useState([
    { id: 'T1', label: 'Table-1' },
    { id: 'T2', label: 'Table-2' },
    { id: 'T3', label: 'Table-3' },
    { id: 'T4', label: 'Table-4' },
    { id: 'T5', label: 'Table-5' }
  ]);
  const [printerEnabled, setPrinterEnabled] = useState(false);
  const [kitchenDisplayEnabled, setKitchenDisplayEnabled] = useState(true);
  const [inventoryEnabled, setInventoryEnabled] = useState(false);

  // Step 4: Staff Setup States
  const [staffName, setStaffName] = useState('');
  const [staffEmail, setStaffEmail] = useState('');
  const [staffPhone, setStaffPhone] = useState('');
  const [staffRole, setStaffRole] = useState('chef'); // chef, manager, staff
  const [tempStaffList, setTempStaffList] = useState([]);

  // Fetch current details on load (in case some default values exist or they are reloading)
  useEffect(() => {
    const fetchExistingData = async () => {
      try {
        const res = await getSetupData();
        if (res.success) {
          const { cafe, paymentConfig, operationalConfig } = res;
          if (cafe) {
            setCafeName(cafe.name || '');
            setAddress(cafe.address || '');
            setLogoUrl(cafe.logoUrl || '');
            if (cafe.logoUrl) setLogoPreview(cafe.logoUrl);
            setMapsLocation(cafe.mapsLocation || '40.7128,-74.0060');
            setOpeningTime(cafe.openingTime || '08:00');
            setClosingTime(cafe.closingTime || '22:00');
            setGstNumber(cafe.gstNumber || '');
            setSupportNumber(cafe.supportNumber || '');
          }
          if (paymentConfig) {
            setRazorpayKeyId(paymentConfig.razorpayKeyId || '');
            setRazorpaySecret(paymentConfig.razorpaySecret || '');
            setUpiId(paymentConfig.upiId || '');
            setBankHolderName(paymentConfig.bankHolderName || '');
            setAccountNumber(paymentConfig.accountNumber || '');
            setIfscCode(paymentConfig.ifscCode || '');
            setIsRazorpayVerified(paymentConfig.isVerified || false);
          }
          if (operationalConfig) {
            setPrinterEnabled(operationalConfig.printerEnabled || false);
            setKitchenDisplayEnabled(operationalConfig.kitchenDisplayEnabled || false);
            setInventoryEnabled(operationalConfig.inventoryEnabled || false);
            if (operationalConfig.tables && operationalConfig.tables.length > 0) {
              setTablesList(operationalConfig.tables);
              setTableCount(operationalConfig.tables.length);
            }
          }
        }
      } catch (err) {
        console.error('Failed to load existing setup data:', err);
      }
    };
    fetchExistingData();
  }, []);

  // Sync table generation when count changes
  const handleTableCountChange = (count) => {
    const newCount = Math.max(1, Math.min(50, Number(count)));
    setTableCount(newCount);

    setTablesList((prev) => {
      const list = [...prev];
      if (list.length < newCount) {
        for (let i = list.length; i < newCount; i++) {
          list.push({ id: `T${i + 1}`, label: `Table-${i + 1}` });
        }
      } else if (list.length > newCount) {
        list.splice(newCount);
      }
      return list;
    });
  };

  const handleTableLabelChange = (index, value) => {
    setTablesList((prev) => {
      const list = [...prev];
      list[index].label = value;
      return list;
    });
  };

  // Upload Logo handler
  const handleLogoUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setLogoFile(file);
    // Visual reader preview
    const reader = new FileReader();
    reader.onload = (event) => {
      setLogoPreview(event.target.result);
    };
    reader.readAsDataURL(file);

    try {
      setLoading(true);
      setErrorMsg('');
      const res = await uploadLogo(file);
      if (res.success && res.logoUrl) {
        setLogoUrl(res.logoUrl);
        setSuccessMsg('Logo uploaded successfully!');
        setTimeout(() => setSuccessMsg(''), 2500);
      }
    } catch (err) {
      setErrorMsg('Logo file upload failed. Max file size is 2MB.');
    } finally {
      setLoading(false);
    }
  };

  // Verify Razorpay Connection
  const testRazorpayConnection = async () => {
    if (!razorpayKeyId || !razorpaySecret) {
      setErrorMsg('Razorpay Key ID and Secret Key are required to verify connection.');
      return;
    }
    setErrorMsg('');
    setSuccessMsg('');
    setVerifyingKeys(true);
    try {
      const res = await verifyRazorpayKeys(razorpayKeyId, razorpaySecret);
      if (res.success) {
        setIsRazorpayVerified(true);
        setSuccessMsg('Razorpay connection verified successfully! Payment Configured.');
      }
    } catch (err) {
      setIsRazorpayVerified(false);
      setErrorMsg(err.response?.data?.message || 'Verification failed. Please check credentials.');
    } finally {
      setVerifyingKeys(false);
    }
  };

  // Add staff locally to register during setup finalize
  const addStaffToRoster = () => {
    if (!staffName || !staffEmail || !staffPhone) {
      setErrorMsg('Please complete all staff details before adding.');
      return;
    }
    setErrorMsg('');

    // Check duplicate email in current temp list
    if (tempStaffList.find(s => s.email.toLowerCase() === staffEmail.toLowerCase())) {
      setErrorMsg('Staff member with this email is already added.');
      return;
    }

    setTempStaffList((prev) => [
      ...prev,
      {
        name: staffName,
        email: staffEmail,
        phone: staffPhone,
        staffRole: staffRole,
        role: ['chef', 'manager'].includes(staffRole) ? staffRole : 'staff'
      }
    ]);

    // Reset inputs
    setStaffName('');
    setStaffEmail('');
    setStaffPhone('');
  };

  const removeStaffFromRoster = (index) => {
    setTempStaffList((prev) => prev.filter((_, i) => i !== index));
  };

  // Final Setup Save
  const handleFinalizeSetup = async () => {
    setErrorMsg('');
    setLoading(true);
    try {
      const setupPayload = {
        logoUrl,
        address,
        mapsLocation,
        openingTime,
        closingTime,
        gstNumber,
        supportNumber: supportNumber || user.phone,
        paymentConfig: {
          razorpayKeyId,
          razorpaySecret,
          upiId,
          bankHolderName,
          accountNumber,
          ifscCode,
          isVerified: isRazorpayVerified
        },
        operationalConfig: {
          tables: tablesList,
          printerEnabled,
          kitchenDisplayEnabled,
          inventoryEnabled
        },
        staffList: tempStaffList
      };

      const res = await saveSetupData(setupPayload);
      if (res.success) {
        // Reload user session details so `setupCompleted` turns true
        await checkSession();
        navigate('/admin');
      }
    } catch (err) {
      setErrorMsg(err.response?.data?.message || 'Error finalizing onboarding setup.');
    } finally {
      setLoading(false);
    }
  };

  // Wizard navigation validations
  const validateAndNext = () => {
    setErrorMsg('');
    if (step === 1) {
      if (!address) {
        setErrorMsg('Cafe address is required.');
        return;
      }
    }
    if (step === 2) {
      if (!razorpayKeyId || !razorpaySecret) {
        setErrorMsg('Razorpay Keys are required to enable ordering payments.');
        return;
      }
      if (!isRazorpayVerified) {
        if (!window.confirm('You have not verified your Razorpay credentials. Proceed anyway?')) {
          return;
        }
      }
    }
    setStep(prev => prev + 1);
  };

  const stepTitles = [
    'Cafe Profile',
    'Payment Setup',
    'Operational Setup',
    'Staff Roster',
    'Complete Onboarding'
  ];

  return (
    <div style={{
      maxWidth: '850px',
      margin: '40px auto',
      padding: '0 20px',
      fontFamily: "'Outfit', sans-serif"
    }}>
      {/* CSS Styles injection for interactive UI */}
      <style>{`
