  const handleToggleActive = async (id, currentStatus) => {
    setErrorMsg('');
    setSuccessMsg('');
    try {
      setLoading(true);
      const data = await updateCafe(id, { isActive: !currentStatus });
      if (data.success) {
        setSuccessMsg(data.message);
        loadCafes();
