        if (selectedCafeForDetails && selectedCafeForDetails._id === id) {
          setSelectedCafeForDetails(prev => ({ ...prev, isActive: !currentStatus }));
        }
      }
    } catch (err) {
      setErrorMsg('Failed to update status.');
    } finally {
      setLoading(false);
    }
  };

